import React, { useEffect, useState } from "react";
import API from "../../api/api";

const Portfolio = () => {
  const [items, setItems]       = useState([]);
  const [loading, setLoading]   = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm]         = useState({ title:"", description:"", link:"", tech_stack:"" });
  const [saving, setSaving]     = useState(false);

  useEffect(() => { fetchPortfolio(); }, []);

  const fetchPortfolio = async () => {
    try {
      const res = await API.get("/portfolio/my");
      setItems(res.data || []);
    } catch(e) {} finally { setLoading(false); }
  };

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async () => {
    if (!form.title) return alert("Title is required");
    setSaving(true);
    try {
      const res = await API.post("/portfolio", form);
      setItems(prev => [{ id: res.data.id, ...form, created_at: new Date().toISOString() }, ...prev]);
      setForm({ title:"", description:"", link:"", tech_stack:"" });
      setShowForm(false);
    } catch(e) { alert("Error saving portfolio"); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this portfolio item?")) return;
    await API.delete(`/portfolio/${id}`);
    setItems(prev => prev.filter(i => i.id !== id));
  };

  if (loading) return <div className="text-center py-10 text-gray-500">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-4xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold text-gray-800">🗂 My Portfolio</h1>
          <button onClick={() => setShowForm(!showForm)}
            className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
            {showForm ? "✕ Cancel" : "+ Add Project"}
          </button>
        </div>

        {/* ADD FORM */}
        {showForm && (
          <div className="bg-white rounded-xl shadow p-6 mb-6 border border-teal-100">
            <h2 className="text-lg font-bold text-gray-700 mb-4">Add Portfolio Item</h2>
            <div className="grid grid-cols-1 gap-4">
              <div>
                <label className="text-sm font-medium text-gray-600 mb-1 block">Project Title *</label>
                <input name="title" value={form.title} onChange={handleChange}
                  placeholder="e.g. E-commerce Website"
                  className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500" />
              </div>
              <div>
                <label className="text-sm font-medium text-gray-600 mb-1 block">Description</label>
                <textarea name="description" value={form.description} onChange={handleChange} rows={3}
                  placeholder="What did you build? What was your role?"
                  className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500 resize-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-sm font-medium text-gray-600 mb-1 block">Project Link</label>
                  <input name="link" value={form.link} onChange={handleChange}
                    placeholder="https://github.com/..."
                    className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500" />
                </div>
                <div>
                  <label className="text-sm font-medium text-gray-600 mb-1 block">Tech Stack</label>
                  <input name="tech_stack" value={form.tech_stack} onChange={handleChange}
                    placeholder="React, Node, MySQL"
                    className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-teal-500" />
                </div>
              </div>
              <button onClick={handleSubmit} disabled={saving}
                className="bg-teal-600 hover:bg-teal-700 text-white py-2 rounded-lg font-medium transition disabled:opacity-50">
                {saving ? "Saving..." : "Save Portfolio Item"}
              </button>
            </div>
          </div>
        )}

        {/* PORTFOLIO GRID */}
        {items.length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center text-gray-400 shadow">
            <div className="text-5xl mb-3">🗂</div>
            <p>No portfolio items yet. Add your first project!</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            {items.map((item) => (
              <div key={item.id} className="bg-white rounded-xl shadow p-5 border border-gray-100 hover:shadow-md transition">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-gray-800 text-lg">{item.title}</h3>
                  <button onClick={() => handleDelete(item.id)}
                    className="text-red-400 hover:text-red-600 text-lg transition">🗑</button>
                </div>
                {item.description && <p className="text-gray-600 text-sm mb-3">{item.description}</p>}
                {item.tech_stack && (
                  <div className="flex flex-wrap gap-2 mb-3">
                    {item.tech_stack.split(",").map((t, i) => (
                      <span key={i} className="bg-teal-50 text-teal-700 px-2 py-0.5 rounded text-xs font-medium">
                        {t.trim()}
                      </span>
                    ))}
                  </div>
                )}
                {item.link && (
                  <a href={item.link} target="_blank" rel="noreferrer"
                    className="text-teal-600 hover:text-teal-700 text-sm font-medium flex items-center gap-1">
                    🔗 View Project
                  </a>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Portfolio;
